1	#!/usr/bin/env node
2	'use strict';
3	// eval/calibration-known-bad/run.js - the earn-your-zero gate.
4	//
5	// Every analyser/gate in tools/ must FAIL on seeded known-bad input each run: a checker
6	// that reports zero findings on its own calibration fixture is broken, and its green
7	// tick on real code is worthless (the confident-zero disease). This runner invokes each
8	// relevant checker in --calibrate mode and FAILS (exit 1) if any checker reports zero
9	// findings on its fixture.
10	//
11	// THE --calibrate CONTRACT (coordinate with the tools/ agent; documented in README.md):
12	//   node tools/<checker> --calibrate
13	//   - the checker scans eval/calibration-known-bad/fixtures/ (this directory) only
14	//   - prints a single JSON object to stdout: {"checker":"<name>","findings":[{"file":"...","line":N,"rule":"...","message":"..."}]}
15	//   - exits 0 whether or not findings exist (--calibrate reports; this runner judges)
16	//
17	// Checker discovery: each entry lists candidate paths under tools/. While the tools/
18	// agent is still building (P0 runs in parallel), a missing checker is reported as
19	// SKIPPED with a warning and does not fail the run - pass --strict to make missing
20	// checkers fail (CI flips to --strict the moment tools/ lands).
21	//
22	// The payload-contract check needs no external tool: it runs payload/contract
23	// validatePayload() directly, so at least one earn-your-zero gate is live from commit 1.
24	//
25	// Usage: node eval/calibration-known-bad/run.js [--strict] [--json]
26	// Exit codes: 0 = every present checker caught its fixture; 1 = a checker reported zero
27	// findings on its fixture (or --strict and a checker is missing); 2 = runner error.
28	
29	const fs = require('fs');
30	const os = require('os');
31	const path = require('path');
32	const { execFileSync } = require('child_process');
33	
34	const REPO_ROOT = path.resolve(__dirname, '..', '..');
35	const FIXTURES_DIR = path.join(__dirname, 'fixtures');
36	
37	// Each calibration: the fixture file(s) the checker must flag, and where the checker
38	// may live under tools/ (first existing candidate wins).
39	const CALIBRATIONS = [
40	  {
41	    name: 'silent-swallow',
42	    description: 'bare/expressionless catch blocks that swallow errors',
43	    fixtures: ['bare-catch-swallow.js'],
44	    checkerCandidates: [
45	      'tools/swallow-gate/check.js',
46	      'tools/silent-swallow/index.js',
47	      'tools/silent-swallow.js',
48	      'tools/sweep/silent-swallow.js',
49	    ],
50	  },
51	  {
52	    name: 'one-door',
53	    description: 'a second producer of the JURISDICTION fact outside facts/jurisdiction.js',
54	    fixtures: ['second-door-jurisdiction.js'],
55	    checkerCandidates: [
56	      'tools/one-door/check.js',
57	      'tools/one-door/index.js',
58	      'tools/one-door.js',
59	      'tools/sweep/one-door.js',
60	    ],
61	  },
62	  {
63	    name: 'catalogue-regex-health',
64	    description: 'over-escaped dead regex in a rule JSON (the dpo[@\\\\s] class)',
65	    fixtures: ['rule-dead-regex.json', 'p2-regex-dead-pattern.json'],
66	    checkerCandidates: [
67	      'catalogue/linters/regex-health.js',
68	      'tools/catalogue-lint/regex-health.js',
69	      'tools/catalogue-lint.js',
70	    ],
71	  },
72	  {
73	    name: 'catalogue-polarity',
74	    description: 'polarity-inverted rule: prohibit-style regex that matches compliant wording',
75	    fixtures: ['rule-polarity-inverted.json', 'p2-polarity-inverted.json'],
76	    checkerCandidates: [
77	      'catalogue/linters/polarity.js',
78	      'tools/catalogue-lint/polarity.js',
79	      'tools/catalogue-lint.js',
80	    ],
81	  },
82	  {
83	    name: 'catalogue-citation-completeness',
84	    description: 'a candidate Compliance Object Model record whose citation.url is not on an official statutory/regulatory host (Constitution Rule 14 / caution.md C-104)',
85	    fixtures: ['p2-citation-missing-official-host.json'],
86	    checkerCandidates: [
87	      'catalogue/linters/citation-completeness.js',
88	      'tools/catalogue-lint/citation-completeness.js',
89	      'tools/catalogue-lint.js',
90	    ],
91	  },
92	  {
93	    name: 'catalogue-threshold-guard',
94	    description: 'a size/turnover-threshold-bearing record with no modelled excluded_when (the Modern Slavery Act-on-an-SME class, caution.md C-071)',
95	    fixtures: ['p2-threshold-missing-excluded.json'],
96	    checkerCandidates: [
97	      'catalogue/linters/threshold-guard.js',
98	      'tools/catalogue-lint/threshold-guard.js',
99	      'tools/catalogue-lint.js',
100	    ],
101	  },
102	  {
103	    name: 'catalogue-only-literals',
104	    description: 'fine amount / regulator name / law title authored as a literal in code',
105	    fixtures: ['fabricated-fine-literal.js'],
106	    checkerCandidates: [
107	      // one-door's fine/regulator/law-title facts ARE the catalogue-only-literals
108	      // enforcement: any such literal outside catalogue/ is a second door.
109	      'tools/one-door/check.js',
110	      'tools/domain-gates/catalogue-only-literals.js',
111	      'tools/catalogue-only-literals.js',
112	      'tools/sweep/domain-gates.js',
113	    ],
114	  },
115	  {
116	    name: 'p1-unreachable-bundle-abstain',
117	    description:
118	      'bot-walled and SPA-shell EvidenceBundles (C-038/C-032): any facts module emitting a non-abstain fact or any finding on them is broken',
119	    fixtures: ['p1-reference-fixtures-unreachable-bundle.json'],
120	    checkerCandidates: [
121	      'tools/domain-gates/unreachable-abstain.js',
122	      'facts/tools/abstain-calibrate.js',
123	      'tools/facts-abstain/check.js',
124	    ],
125	  },
126	  {
127	    name: 'identity-marketing-headline',
128	    description:
129	      'facts/identity.js must refuse a marketing headline with HTML entity residue as display_name/slug (the amp-slug class, caution C-003)',
130	    fixtures: ['p1-identity-marketing-headline.json'],
131	    checkerCandidates: [
132	      // the identity module IS the gate here: --calibrate replays every
133	      // p1-identity-*.json fixture and emits a finding per refused poison
134	      'facts/identity.js',
135	    ],
136	  },
137	  {
138	    name: 'payload-contract',
139	    description: 'payload missing REQUIRED contract fields must validate non-empty missing[]',
140	    fixtures: ['payload-missing-fields.json'],
141	    internal: true, // runs payload/contract directly; live from commit 1
142	  },
143	];
144	
145	function findChecker(candidates) {
146	  for (const rel of candidates || []) {
147	    const abs = path.join(REPO_ROOT, rel);
148	    if (fs.existsSync(abs)) return abs;
149	  }
150	  return null;
151	}
152	
153	// Two checker dialects are accepted:
154	//   a) stdout dialect: `--calibrate` prints {"checker":"...","findings":[...]} to stdout, exit 0.
155	//   b) gate-cli dialect (tools/lib/gate-cli.js): `--calibrate --json <path>` writes a findings
156	//      ARRAY to <path>, prints human text to stdout, and exits 1 when zero violations were
157	//      found. A non-zero exit is therefore NOT a runner error here: we still read the JSON
158	//      file and let this runner judge the (possibly empty) findings list.
159	// runCalibrateProcess(checkerPath, jsonOut) -> stdout from spawning the checker's --calibrate
160	// contract, having already validated its exit status against the two runner-judged states.
161	// The --calibrate contract has exactly two runner-judged statuses: 0 (checker found violations) and
162	// 1 (checker found ZERO on its fixtures - the caller then FAILs that calibration from the empty
163	// findings list). Exit 2 means the checker's OWN self-test failed: it is a broken tool and can
164	// NEVER earn a PASS, no matter what findings it managed to write. A broken self-test masked by
165	// parsed findings is the unearned-zero disease (Constitution Rule 4), so reject it unconditionally.
166	function runCalibrateProcess(checkerPath, jsonOut) {
167	  let stdout = '';
168	  let status = 0;
169	  try {
170	    stdout = execFileSync(process.execPath, [checkerPath, '--calibrate', '--json', jsonOut], {
171	      cwd: REPO_ROOT,
172	      encoding: 'utf8',
173	      timeout: 120000,
174	    });
175	  } catch (e) {
176	    // gate-cli exits 1 on zero calibration findings and 2 on a failed self-test. Keep the
177	    // stdout we got; if the checker wrote no JSON file either, the throw below reports it.
178	    stdout = (e.stdout || '') + '';
179	    status = (typeof e.status === 'number') ? e.status : 2;
180	  }
181	  if (status === 2) {
182	    throw new Error('checker self-test FAILED (exit 2): it cannot see the class it exists to catch, so its calibration result is void and cannot be masked by any parsed findings');
183	  }
184	  if (status !== 0 && status !== 1) {
185	    throw new Error('checker exited with undocumented --calibrate status ' + status + ' (expected 0 = findings, 1 = zero-findings, 2 = broken self-test)');
186	  }
187	  return stdout;
188	}
189	
190	// safeJsonParse(text) -> the parsed JSON value, or null when `text` is not valid JSON. Used for
191	// the stdout dialect: a non-JSON stdout just means the checker uses the file dialect instead.
192	function safeJsonParse(text) {
193	  try {
194	    return JSON.parse(text);
195	  } catch (e) {
196	    return null; // FAIL-OPEN: non-JSON stdout just means the checker uses the file dialect; handled by the caller.
197	  }
198	}
199	
200	// findingsFromParsed(parsed) -> a findings array if `parsed` looks like a --calibrate findings
201	// payload (a bare array, or {findings:[...]}), else null.
202	function findingsFromParsed(parsed) {
203	  if (Array.isArray(parsed)) return parsed;
204	  if (parsed && Array.isArray(parsed.findings)) return parsed.findings;
205	  return null;
206	}
207	
208	function runExternalChecker(checkerPath) {
209	  const jsonOut = path.join(fs.mkdtempSync(path.join(os.tmpdir(), 'calibrate-')), 'findings.json');
210	  const stdout = runCalibrateProcess(checkerPath, jsonOut);
211	  if (fs.existsSync(jsonOut)) {
212	    const fromFile = findingsFromParsed(JSON.parse(fs.readFileSync(jsonOut, 'utf8')));
213	    if (fromFile) return fromFile;
214	  }
215	  const fromStdout = findingsFromParsed(safeJsonParse(stdout));
216	  if (fromStdout) return fromStdout;
217	  throw new Error('checker emitted neither {findings:[]} JSON on stdout nor a findings JSON file via --json');
218	}
219	
220	function runInternalPayloadContract(fixtureAbs) {
221	  const contract = require(path.join(REPO_ROOT, 'payload', 'contract'));
222	  const payload = JSON.parse(fs.readFileSync(fixtureAbs, 'utf8'));
223	  const missing = contract.validatePayload(payload);
224	  return missing.map((m) => ({ file: fixtureAbs, rule: 'payload-contract', message: `missing: ${m}` }));
225	}
226	
227	// checkMissingFixtures(cal, fixtureAbs) -> {entries, failed, skipped: 0}. entries is non-empty
228	// only when at least one of this calibration's fixture files does not exist on disk.
229	function checkMissingFixtures(cal, fixtureAbs) {
230	  const entries = [];
231	  let failed = 0;
232	  for (const f of fixtureAbs) {
233	    if (!fs.existsSync(f)) {
234	      entries.push({ name: cal.name, status: 'FAIL', detail: `fixture missing: ${f}` });
235	      failed++;
236	    }
237	  }
238	  return { entries, failed, skipped: 0 };
239	}
240	
241	// runInternalCalibration(cal, fixtureAbs) -> {entries, failed, skipped: 0}. The "internal": true
242	// calibration (payload-contract) runs payload/contract's validatePayload() directly rather than
243	// spawning an external checker.
244	function runInternalCalibration(cal, fixtureAbs) {
245	  const entries = [];
246	  let failed = 0;
247	  try {
248	    const findings = runInternalPayloadContract(fixtureAbs[0]);
249	    if (findings.length > 0) {
250	      entries.push({ name: cal.name, status: 'PASS', detail: `${findings.length} finding(s) on the fixture (e.g. ${findings[0].message})` });
251	    } else {
252	      entries.push({ name: cal.name, status: 'FAIL', detail: 'validatePayload() returned an EMPTY missing list on a deliberately incomplete payload - the contract gate is broken' });
253	      failed++;
254	    }
255	  } catch (e) {
256	    entries.push({ name: cal.name, status: 'FAIL', detail: `internal check errored: ${e.message}` });
257	    failed++;
258	  }
259	  return { entries, failed, skipped: 0 };
260	}
261	
262	// missingCheckerResult(cal, strict) -> the {entries,failed,skipped} result when no checker under
263	// tools/ was found for this calibration: FAIL in --strict mode (a fixture without a live checker
264	// is an unearned zero), SKIPPED otherwise (tools/ agent has not landed this gate yet).
265	function missingCheckerResult(cal, strict) {
266	  const detail = `no checker found (looked at: ${cal.checkerCandidates.join(', ')})`;
267	  if (strict) {
268	    return { entries: [{ name: cal.name, status: 'FAIL', detail: `${detail} - strict mode: a fixture without a live checker is an unearned zero` }], failed: 1, skipped: 0 };
269	  }
270	  return { entries: [{ name: cal.name, status: 'SKIPPED', detail: `${detail} - tools/ agent has not landed this gate yet; CI must flip to --strict when it does` }], failed: 0, skipped: 1 };
271	}
272	
273	// judgeCheckerFindings(cal, checker) -> {entries, failed} from running the checker and confirming
274	// EVERY fixture listed for this calibration was caught (CR-38: a multi-fixture calibration
275	// previously passed as long as ONE fixture produced a finding, so a checker could keep catching an
276	// old fixture while missing a new one).
277	function judgeCheckerFindings(cal, checker) {
278	  const findings = runExternalChecker(checker);
279	  const missingFixtures = cal.fixtures.filter((fx) => !findings.some((fd) => String(fd.file || '').includes(fx)));
280	  const fixtureHits = findings.filter((fd) => cal.fixtures.some((fx) => String(fd.file || '').includes(fx)));
281	  if (missingFixtures.length === 0) {
282	    return { entries: [{ name: cal.name, status: 'PASS', detail: `${fixtureHits.length} finding(s) across all ${cal.fixtures.length} fixture(s) via ${path.relative(REPO_ROOT, checker)}` }], failed: 0 };
283	  }
284	  return { entries: [{ name: cal.name, status: 'FAIL', detail: `${path.relative(REPO_ROOT, checker)} reported ZERO findings on: ${missingFixtures.join(', ')} - it has not earned its zero on every seeded fixture (${cal.description})` }], failed: 1 };
285	}
286	
287	// runExternalCalibration(cal, strict) -> {entries, failed, skipped}. Locates the checker under
288	// tools/ via findChecker(), reports SKIPPED (or FAIL in --strict mode) if none is found yet, and
289	// otherwise runs its --calibrate contract via runExternalChecker() and checks every listed
290	// fixture was caught. Behaviour is unchanged from the original inline version: failed/skipped are
291	// still exactly 0 or 1 per call (missingCheckerResult and judgeCheckerFindings each push exactly
292	// one entry and increment their own counter by at most 1).
293	function runExternalCalibration(cal, strict) {
294	  const checker = findChecker(cal.checkerCandidates);
295	  if (!checker) return missingCheckerResult(cal, strict);
296	  try {
297	    const { entries, failed } = judgeCheckerFindings(cal, checker);
298	    return { entries, failed, skipped: 0 };
299	  } catch (e) {
300	    return { entries: [{ name: cal.name, status: 'FAIL', detail: `checker errored or broke the --calibrate contract: ${e.message}` }], failed: 1, skipped: 0 };
301	  }
302	}
303	
304	// runOneCalibration(cal, strict) -> {entries: [...], failed: N, skipped: N} for one CALIBRATIONS
305	// entry. Semantics are UNCHANGED from the original inline loop body (do not change the
306	// CALIBRATIONS registry semantics or --strict behaviour): missing fixture files short-circuit
307	// straight to a FAIL entry per file; otherwise an "internal" calibration runs payload/contract
308	// directly and everything else runs its checker's --calibrate contract. The original loop tested
309	// `results.some((r) => r.name === cal.name && r.status === 'FAIL')` against the GLOBAL results
310	// list; since every entry pushed for earlier calibrations carries a DIFFERENT cal.name, that was
311	// already equivalent to testing only the entries just pushed for THIS calibration, which is what
312	// checkMissingFixtures's own (per-calibration) entries list does directly.
313	function runOneCalibration(cal, strict) {
314	  const fixtureAbs = cal.fixtures.map((f) => path.join(FIXTURES_DIR, f));
315	  const missing = checkMissingFixtures(cal, fixtureAbs);
316	  if (missing.entries.length > 0) return missing;
317	  if (cal.internal) return runInternalCalibration(cal, fixtureAbs);
318	  return runExternalCalibration(cal, strict);
319	}
320	
321	// report({strict, results, failed, skipped, asJson}) -> prints the run's summary in --json or
322	// human form, unchanged from the original inline block in main() (params bundled into one object;
323	// not exported, so the call site below is the only caller to update).
324	function report({ strict, results, failed, skipped, asJson }) {
325	  if (asJson) {
326	    console.log(JSON.stringify({ strict, results, failed, skipped }, null, 2));
327	    return;
328	  }
329	  console.log('calibration-known-bad: the earn-your-zero gate');
330	  for (const r of results) console.log(`  ${r.status.padEnd(7)} ${r.name}: ${r.detail}`);
331	  if (failed > 0) {
332	    console.log(`RESULT: FAIL - ${failed} gate(s) did not catch their seeded known-bad fixture. A gate that misses planted disease is reporting worthless greens.`);
333	  } else if (skipped > 0) {
334	    console.log(`RESULT: OK with ${skipped} SKIPPED - external checkers not landed yet. Flip CI to --strict once tools/ lands.`);
335	  } else {
336	    console.log('RESULT: OK - every gate caught its fixture.');
337	  }
338	}
339	
340	function main(argv) {
341	  const args = argv.slice(2);
342	  const strict = args.includes('--strict');
343	  const asJson = args.includes('--json');
344	  const unknown = args.filter((a) => !['--strict', '--json'].includes(a));
345	  if (unknown.length) {
346	    console.error(`Unknown argument(s): ${unknown.join(', ')}`);
347	    return 2;
348	  }
349	
350	  const results = [];
351	  let failed = 0;
352	  let skipped = 0;
353	
354	  for (const cal of CALIBRATIONS) {
355	    const r = runOneCalibration(cal, strict);
356	    results.push(...r.entries);
357	    failed += r.failed;
358	    skipped += r.skipped;
359	  }
360	
361	  report({ strict, results, failed, skipped, asJson });
362	  return failed > 0 ? 1 : 0;
363	}
364	
365	if (require.main === module) {
366	  process.exit(main(process.argv));
367	}
368	
369	module.exports = { CALIBRATIONS, runExternalChecker };
370

