1	'use strict';
2	// CALIBRATION FIXTURE (known-bad INPUT, self-testing dialect) for evidence/browser/observe.js.
3	//
4	// THE DISEASE (caution.md C-040): a stuck Chromium once held a mint hostage for 752 seconds because
5	// the browser's own goto timeout did not bound launch + networkidle. observe() must make that
6	// STRUCTURALLY IMPOSSIBLE: its ONE outer Promise.race deadline covers launch -> observe -> close, so
7	// a browser that never returns from goto is refused with lane:{ran:false, reason:'deadline'} rather
8	// than hanging the mint. This fixture is the seeded proof: a scripted browser whose goto NEVER
9	// settles. The gate (observe's deadline) EARNS ITS ZERO only if it refuses this hang.
10	//
11	// DIALECT (earn-your-zero polarity, matching the p1-jurisdiction fixture and run.js semantics):
12	//   calibrate() returns a findings ARRAY - one finding when the trap is CORRECTLY refused, an EMPTY
13	//   array (misses written to stderr) when observe() failed to bound the hang. A strict runner that
14	//   requires non-empty findings therefore fails exactly when the deadline has regressed.
15	//   Standalone: `node eval/calibration-known-bad/fixtures/p3-browser-deadline.js` exits 1 on a miss.
16	//
17	// The fixture GUARDS ITSELF against a true hang: it races observe() against a wall-clock guard, so a
18	// regression that makes observe() hang is reported as a MISS, never an actual hang of this process.
19	
20	const path = require('path');
21	const { observe } = require(path.resolve(__dirname, '..', '..', '..', 'evidence', 'browser', 'observe.js'));
22	
23	const DEADLINE_MS = 25;   // a tiny CAP for the fixture; the real default is 45000 (a cap, never a floor)
24	const GUARD_MS = 1500;    // generous wall-clock guard for a loaded CI runner; far below the 752s class
25	
26	// A scripted browser whose page.goto() NEVER settles - the exact 752s shape, in a fake.
27	function hangingLaunch() {
28	  const page = {
29	    on() {},
30	    goto() { return new Promise(() => {}); }, // HANG: never resolves, no timer
31	    async settle() {},
32	    async cookies() { return []; },
33	    async findConsentControl() { return null; },
34	    async clickConsent() {},
35	  };
