'use strict';
// Ad hoc verification script (NOT part of the repo) - checks evidence/crawler/coverage-contract.js
// against p3-crawl-substring-classify.json and against the core "crawl poverty" screening behaviour
// (an unreachable/thin crawl must screen out absence findings, never assert on unread content).
// Run: node verify-coverage-contract.js

const path = require('path');
const fs = require('fs');
const REPO = '/Users/amanigga/Desktop/TAMAZIA-REBUILD/tamazia-audit-engine';
const cc = require(path.join(REPO, 'evidence/crawler/coverage-contract.js'));

let failures = 0;

// 1) classify() against every case in the real fixture
const fixture = JSON.parse(fs.readFileSync(path.join(REPO, 'eval/calibration-known-bad/fixtures/p3-crawl-substring-classify.json'), 'utf8'));
for (const c of fixture.cases) {
  const got = cc.classify(c.url);
  const ok = got === c.expect;
  console.log((ok ? 'PASS' : 'FAIL') + '  ' + c.url + '  expect=' + c.expect + ' got=' + got + (c.trap ? ' (trap=' + c.trap + ')' : ''));
  if (!ok) failures++;
  if (c.trap && got === c.trap) { console.log('   TRAP HIT: classified as the substring-trap class, not the correct class'); failures++; }
}

// 2) crawl-poverty: an empty/unreachable crawl must screen, never assessable
const emptyCov = cc.computeCoverage([], 'law-firms');
console.log('\nempty crawl computeCoverage:', JSON.stringify(emptyCov));
if (emptyCov.render_class !== 'screened') { console.log('FAIL: empty crawl did not screen'); failures++; }
else console.log('PASS: empty crawl correctly screens (render_class=screened)');

// 3) applyCoverage must drop 'miss' findings when screened
const findings = [{ id: 'f1', status: 'miss' }, { id: 'f2', status: 'pass' }];
const applied = cc.applyCoverage(findings, emptyCov);
console.log('applyCoverage on screened site:', JSON.stringify(applied));
if (applied.some((f) => f.status === 'miss')) { console.log('FAIL: a miss finding survived a screened site'); failures++; }
else console.log('PASS: miss findings dropped on a screened (unread) site');

// 4) a full, well-covered crawl must be assessable
const fullPages = [
  { url: 'https://x.example/' }, { url: 'https://x.example/privacy-policy' },
  { url: 'https://x.example/complaints-procedure' }, { url: 'https://x.example/pricing' },
];
const fullCov = cc.computeCoverage(fullPages, 'law-firms');
console.log('\nfull crawl computeCoverage:', JSON.stringify(fullCov));
if (fullCov.render_class !== 'assessable') { console.log('FAIL: a well-covered crawl did not become assessable'); failures++; }
else console.log('PASS: a well-covered crawl is assessable');

console.log('\n' + (failures === 0 ? 'ALL VERIFIED OK' : failures + ' VERIFICATION FAILURE(S)'));
process.exit(failures === 0 ? 0 : 1);

