2	'use strict';
3	/**
4	 * HISTORY-REGRESSION: every historical failure class must name a live guarding gate, forever.
5	 *
6	 * The old estate died of the same ~256 defects, 6 corroborated ACT facts and 5 engine-semantic
7	 * domain-gate classes over and over. docs/failure-ledger/crossref.json maps each to a failure
8	 * class and the ONE file in THIS repo that catches its class. This checker reads that ledger and
9	 * makes "a historical failure class with no live guarding gate" a CI-visible state that cannot be
10	 * quietly forgotten.
11	 *
12	 * WHAT FAILS THE BUILD (exit 1):
13	 *   1. no-gate-named       a class whose catching_gate is empty or the literal "MISSING".
14	 *                          Nobody has even named the gate that must exist. This is the pure
15	 *                          "catching_gate MISSING" case from the spec.
16	 *   2. guarded-gate-missing a class marked status=guarded whose catching_gate file does NOT exist
17	 *                          in the tree. A guarded class is CLAIMING live protection; if the file
18	 *                          is gone, the claim is a lie (a deleted gate, a typo'd path, a false
19	 *                          "we cover this"). This is the "names a file that does not exist" case,
20	 *                          scoped to the classes that assert they are protected.
21	 *   3. gap-no-phase        a class marked status=gap with no phase (P0..P9) that closes it. A gap
22	 *                          with no committed phase is an unowned hole, not a plan.
23	 *   4. gap-gate-landed     a class marked status=gap whose planned catching_gate NOW EXISTS. The
24	 *                          gate arrived; the ledger must be flipped to guarded (and the crossref
25	 *                          rebuilt) so the ledger never understates live coverage.
26	 *   5. bad-status / unknown-class / defect-class-mismatch  structural integrity of the ledger.
27	 *
28	 * WHAT IS REPORTED BUT DOES NOT FAIL (the honest deferred state, Constitution Rule 4 phasing):
29	 *   a class marked status=gap whose planned catching_gate does not exist YET, and which carries a
30	 *   valid future phase. These are the genuinely-unguardable-until-Pn classes (render truth-pack,
31	 *   the mint pipeline, the LLM chain). They are printed loudly and counted every single run, so
32	 *   the gap is impossible to forget, but they do not turn CI permanently red at P0 - a red build
33	 *   nobody can make green is theatre (caution.md C-163). The GAPS.md file ranks them for the
34	 *   phases that must close them.
35	 *
36	 * This split is deliberate and matches the task's honesty rule: do not force-fit a class to a live
37	 * gate it is not actually policed by; mark it gap with the phase, and let this checker keep the
38	 * hole visible until the phase lands (at which point rule 4 forces the ledger to catch up).
39	 *
40	 * Modes (the tools/lib/gate-cli.js dialect; see tools/swallow-gate/check.js for the same contract):
41	 *   node tools/history-regression/check.js                 validate the committed crossref, exit 1
42	 *                                                          on any integrity violation
43	 *   node tools/history-regression/check.js --calibrate     validate the seeded broken fixture
44	 *                                                          (tools/history-regression/fixtures/) and
45	 *                                                          REQUIRE the fabricated missing gate is
46	 *                                                          caught; zero violations found = exit 1
47	 *   node tools/history-regression/check.js --json <path>   also write findings JSON for the sweep
48	 */
49	const fs = require('fs');
50	const path = require('path');
51	
52	const { parseGateArgs, ROOT } = require('../lib/gate-cli');
53	const safePath = require('../lib/safe-path.js');
54	
55	const NAME = 'history-regression';
56	const CROSSREF = path.join(ROOT, 'docs', 'failure-ledger', 'crossref.json');
57	const FIXTURE = path.join(__dirname, 'fixtures', 'crossref.broken.json');
58	const PHASE_RX = /^P[0-9]$/;
59	
60	// gateExists is injected so the calibration fixture can name gates that "exist" or "do not exist"
61	// deterministically without touching the real filesystem: by default it stats the real repo tree.
62	// A catching_gate must be a repo-relative path INSIDE the tree: an absolute path or a "../.." escape
63	// is rejected before the existence check, so a class can never satisfy a guarded claim by pointing
64	// at an unrelated host file outside the repo (Rule: hosts/paths are validated, never trusted raw).
65	function realGateExists(rel) {
66	  // isSafeRelativePath is the non-throwing boolean form of the single path door: an absolute path or
67	  // a "../.." escape is rejected here (returns false), so a class can never satisfy a guarded claim by
68	  // pointing at a host file outside the repo.
69	  if (!safePath.isSafeRelativePath(rel)) return false;
70	  // A gate must be a real REGULAR FILE inside the repo: existsSync is true for a directory, and
71	  // statSync FOLLOWS symlinks, so a repo-local link pointing at an external file would still count
72	  // (CR round-5). lstatSync stats the entry ITSELF - a symlink's lstat is never isFile(), so only a
73	  // genuine in-tree regular file satisfies the claim. throwIfNoEntry:false makes a MISSING path
74	  // return undefined (fail closed) with no swallowing catch to justify.
75	  const st = fs.lstatSync(path.resolve(ROOT, rel), { throwIfNoEntry: false });
76	  return Boolean(st) && st.isFile();
77	}
78	
79	// validateClassIdentifiers(taxonomy) -> violations[] for missing/duplicate class ids. Run BEFORE the
80	// known/byClass Set+Map are built: those collapse duplicate keys silently, so two conflicting rows
81	// for one class would both validate while defects bind only to the last (one door per class). The
82	// normalisation (String, trimmed) matches the per-row cls value used elsewhere.
83	function validateClassIdentifiers(taxonomy) {
84	  const violations = [];
85	  const seen = new Set();
86	  for (const t of taxonomy) {
87	    const raw = t && t.class;
88	    const cls = typeof raw === 'string' ? raw.trim() : '';
89	    if (!cls) {
90	      violations.push({ class: '(unnamed)', kind: 'no-class', detail: 'a taxonomy row has a missing or empty class identifier; every row must name exactly one class.' });
91	      continue;
92	    }
93	    if (seen.has(cls)) {
94	      violations.push({ class: cls, kind: 'duplicate-class', detail: 'class "' + cls + '" appears in more than one taxonomy row; class identifiers must be unique (one door per class), or a conflicting row is silently dropped by the lookup map.' });
95	    }
96	    seen.add(cls);
97	  }
98	  return violations;
99	}
100	
101	// classifyGuardedRow / classifyGapRow / validateTaxonomyRow -> the per-row rule engine, each owning
102	// one nesting-inducing branch so no single function exceeds the health caps.
103	function classifyGuardedRow(cls, gate, gateExists) {
104	  if (gateExists(gate)) return null; // rule 2 satisfied
105	  return { class: cls, kind: 'guarded-gate-missing', detail: 'status=guarded but catching_gate "' + gate + '" does not exist. A class claiming live protection must point at a real file; a deleted or mistyped gate is a false claim of coverage.' };
106	}
107	
108	// classifyGapRow(row, gateExists, deferred) where row = { cls, gate, t }. Bundled into one row object
109	// so the signature stays within the argument cap (CR round-4: <=4 formal parameters).
110	function classifyGapRow(row, gateExists, deferred) {
111	  const { cls, gate, t } = row;
112	  // rule 3: a gap must carry a phase that closes it.
113	  if (!t.phase || !PHASE_RX.test(String(t.phase))) {
114	    return { class: cls, kind: 'gap-no-phase', detail: 'status=gap with no valid phase (expected P0..P9). A gap with no committed phase is an unowned hole, not a plan.' };
115	  }
116	  // rule 4: the planned gate has landed; the ledger must be flipped to guarded.
117	  if (gateExists(gate)) {
118	    return { class: cls, kind: 'gap-gate-landed', detail: 'status=gap but its planned catching_gate "' + gate + '" now EXISTS. Flip this class to guarded and rebuild the crossref (npm run history:build) so the ledger does not understate live coverage.' };
119	  }
120	  deferred.push({ class: cls, phase: String(t.phase), gate, past_severity: t.past_severity || '?' });
121	  return null;
122	}
123	
124	// rowClassAndGate(t) -> the normalised { cls, gate } for one taxonomy row: a trimmed class id (or
125	// "(unnamed)") and a trimmed catching_gate string (or ""). Factored out so validateTaxonomyRow stays
126	// a thin dispatcher under the complexity cap.
127	function rowClassAndGate(t) {
128	  const cls = t && t.class ? String(t.class) : '(unnamed)';
129	  const gate = t && typeof t.catching_gate === 'string' ? t.catching_gate.trim() : '';
130	  return { cls, gate };
131	}
132	
133	// validateTaxonomyRow(t, gateExists, counters, deferred) -> a violation object or null, incrementing
134	// counters.guarded / counters.gap as it classifies one row (rules 1, 2, 3, 4, 5a).
135	function validateTaxonomyRow(t, gateExists, counters, deferred) {
136	  const { cls, gate } = rowClassAndGate(t);
137	  if (!gate || gate === 'MISSING') {
138	    return { class: cls, kind: 'no-gate-named', detail: 'catching_gate is empty or "MISSING": no gate has been named for this historical failure class.' };
139	  }
140	  if (t.status === 'guarded') { counters.guarded++; return classifyGuardedRow(cls, gate, gateExists); }
141	  if (t.status === 'gap') { counters.gap++; return classifyGapRow({ cls, gate, t }, gateExists, deferred); }
142	  return { class: cls, kind: 'bad-status', detail: 'status must be "guarded" or "gap"; got "' + String(t.status) + '".' };
143	}
144	
145	// validateDefects(defects, known, byClass) -> violations[] (rule 5b): every defect references a known
146	// class with a consistent gate + status (one door per class).
147	function validateDefects(defects, known, byClass) {
148	  const violations = [];
149	  for (const d of defects) {
150	    if (!known.has(d.class)) {
151	      violations.push({ class: String(d.class), kind: 'unknown-class', detail: 'defect ' + (d.id || '?') + ' is tagged with class "' + d.class + '" which has no taxonomy row.' });
152	      continue;
153	    }
154	    const t = byClass.get(d.class);
155	    if (d.catching_gate !== t.catching_gate || d.status !== t.status) {
156	      violations.push({ class: String(d.class), kind: 'defect-class-mismatch', detail: 'defect ' + (d.id || '?') + ' carries catching_gate/status that disagree with its class row (one door per class).' });
157	    }
158	  }
159	  return violations;
160	}
161	
162	// indexTaxonomy(taxonomy) -> { known, byClass }: the Set of class ids and the class->row Map the defect
163	// validation reads. Built after validateClassIdentifiers has already flagged duplicates, so the silent
164	// last-wins collapse of these structures is never load-bearing.
165	function indexTaxonomy(taxonomy) {
166	  const known = new Set(taxonomy.map((t) => t && t.class));
167	  const byClass = new Map(taxonomy.map((t) => [t && t.class, t]));
168	  return { known, byClass };
169	}
170	
171	// validate(doc, gateExists) -> { violations, guarded, gap, deferred }
172	// Pure over its inputs (Constitution: pure functions over explicit inputs). Never reads argv,
173	// never exits; the CLI wrapper decides exit codes.
174	function validate(doc, gateExists) {
175	  const taxonomy = Array.isArray(doc && doc.taxonomy) ? doc.taxonomy : null;
176	  if (!taxonomy) {
177	    return { violations: [{ class: '(document)', kind: 'no-taxonomy', detail: 'crossref.json has no taxonomy array; nothing can be validated.' }], guarded: 0, gap: 0, deferred: [] };
178	  }
179	
180	  const violations = validateClassIdentifiers(taxonomy);
181	  const { known, byClass } = indexTaxonomy(taxonomy);
182	  const counters = { guarded: 0, gap: 0 };
183	  const deferred = []; // gap classes correctly awaiting a future phase (reported, not failed)
184	
185	  for (const t of taxonomy) {
186	    const v = validateTaxonomyRow(t, gateExists, counters, deferred);
187	    if (v) violations.push(v);
188	  }
189	  violations.push(...validateDefects(Array.isArray(doc.defects) ? doc.defects : [], known, byClass));
190	
191	  return { violations, guarded: counters.guarded, gap: counters.gap, deferred };
192	}
193	
194	// SELF_TEST_CASES: one document per violation kind (plus two clean controls), each asserting the
195	// EXACT set of kinds validate() must emit - a partially broken checker cannot pass by tripping on
196	// some unrelated violation (caution.md C-149; hoisted to module scope so selfTest stays a thin loop
197	// under the health caps). exists() treats only 'live/gate.js' as present in the fake tree.
198	const SELF_TEST_GATE_EXISTS = (rel) => rel === 'live/gate.js';
199	const SELF_TEST_CASES = [
200	  { name: 'guarded gate present -> clean', doc: { taxonomy: [{ class: 'a', catching_gate: 'live/gate.js', status: 'guarded' }], defects: [] }, wantKinds: [] },
201	  { name: 'guarded gate missing -> guarded-gate-missing', doc: { taxonomy: [{ class: 'a', catching_gate: 'ghost/gate.js', status: 'guarded' }], defects: [] }, wantKinds: ['guarded-gate-missing'] },
202	  { name: 'MISSING literal -> no-gate-named', doc: { taxonomy: [{ class: 'a', catching_gate: 'MISSING', status: 'guarded' }], defects: [] }, wantKinds: ['no-gate-named'] },
