150	// collectDefects(sweep) -> the full defect list: the classified sweep clusters, the 5 domain-gate
151	// classes (engine-semantic defects no marketplace tool found), and the 6 ACT items (>=2 tools agree,
152	// recorded as their own entries so the ledger names them directly).
153	function sweepDefects(sweep) {
154	  return sweep.findings.map((f, i) => entryFor(classForSweep(f), {
155	    id: 'SW-' + String(i + 1).padStart(4, '0'),
156	    source: 'sweep',
157	    act: (f.corroboration || 0) >= 2,
158	    severity: f.severity,
159	    category: f.category,
160	    corroboration: f.corroboration || 0,
161	    tools: f.tools || [],
162	    path: f.path,
163	    message: f.message,
164	    fingerprint: f.fingerprint,
165	  }));
166	}
