188	function findChecker(candidates) {
189	  for (const rel of candidates || []) {
190	    const abs = path.join(REPO_ROOT, rel);
191	    if (fs.existsSync(abs)) return abs;
192	  }
193	  return null;
194	}
195	
196	// Two checker dialects are accepted:
197	//   a) stdout dialect: `--calibrate` prints {"checker":"...","findings":[...]} to stdout, exit 0.
198	//   b) gate-cli dialect (tools/lib/gate-cli.js): `--calibrate --json <path>` writes a findings
199	//      ARRAY to <path>, prints human text to stdout, and exits 1 when zero violations were
200	//      found. A non-zero exit is therefore NOT a runner error here: we still read the JSON
201	//      file and let this runner judge the (possibly empty) findings list.
202	// runCalibrateProcess(checkerPath, jsonOut) -> stdout from spawning the checker's --calibrate
203	// contract, having already validated its exit status against the two runner-judged states.
204	// The --calibrate contract has exactly two runner-judged statuses: 0 (checker found violations) and
205	// 1 (checker found ZERO on its fixtures - the caller then FAILs that calibration from the empty
206	// findings list). Exit 2 means the checker's OWN self-test failed: it is a broken tool and can
207	// NEVER earn a PASS, no matter what findings it managed to write. A broken self-test masked by
208	// parsed findings is the unearned-zero disease (Constitution Rule 4), so reject it unconditionally.
209	function runCalibrateProcess(checkerPath, jsonOut) {
210	  let stdout = '';
211	  let status = 0;
212	  try {
213	    stdout = execFileSync(process.execPath, [checkerPath, '--calibrate', '--json', jsonOut], {
214	      cwd: REPO_ROOT,
215	      encoding: 'utf8',
216	      timeout: 120000,
217	    });
218	  } catch (e) {
219	    // gate-cli exits 1 on zero calibration findings and 2 on a failed self-test. Keep the
220	    // stdout we got; if the checker wrote no JSON file either, the throw below reports it.
221	    stdout = (e.stdout || '') + '';
222	    status = (typeof e.status === 'number') ? e.status : 2;
223	  }
224	  if (status === 2) {
225	    throw new Error('checker self-test FAILED (exit 2): it cannot see the class it exists to catch, so its calibration result is void and cannot be masked by any parsed findings');
226	  }
227	  if (status !== 0 && status !== 1) {
228	    throw new Error('checker exited with undocumented --calibrate status ' + status + ' (expected 0 = findings, 1 = zero-findings, 2 = broken self-test)');
229	  }
230	  return stdout;
231	}
232	
233	// safeJsonParse(text) -> the parsed JSON value, or null when `text` is not valid JSON. Used for
234	// the stdout dialect: a non-JSON stdout just means the checker uses the file dialect instead.
235	function safeJsonParse(text) {
236	  try {
237	    return JSON.parse(text);
238	  } catch (e) {
239	    return null; // FAIL-OPEN: non-JSON stdout just means the checker uses the file dialect; handled by the caller.
240	  }
241	}
242	
243	// findingsFromParsed(parsed) -> a findings array if `parsed` looks like a --calibrate findings
244	// payload (a bare array, or {findings:[...]}), else null.
245	function findingsFromParsed(parsed) {
246	  if (Array.isArray(parsed)) return parsed;
247	  if (parsed && Array.isArray(parsed.findings)) return parsed.findings;
248	  return null;
249	}
250	
251	function runExternalChecker(checkerPath) {
252	  const jsonOut = path.join(fs.mkdtempSync(path.join(os.tmpdir(), 'calibrate-')), 'findings.json');
253	  const stdout = runCalibrateProcess(checkerPath, jsonOut);
254	  if (fs.existsSync(jsonOut)) {
255	    const fromFile = findingsFromParsed(JSON.parse(fs.readFileSync(jsonOut, 'utf8')));
256	    if (fromFile) return fromFile;
257	  }
258	  const fromStdout = findingsFromParsed(safeJsonParse(stdout));
259	  if (fromStdout) return fromStdout;
260	  throw new Error('checker emitted neither {findings:[]} JSON on stdout nor a findings JSON file via --json');
261	}
262	
263	function runInternalPayloadContract(fixtureAbs) {
264	  const contract = require(path.join(REPO_ROOT, 'payload', 'contract'));
265	  const payload = JSON.parse(fs.readFileSync(fixtureAbs, 'utf8'));
266	  const missing = contract.validatePayload(payload);
267	  return missing.map((m) => ({ file: fixtureAbs, rule: 'payload-contract', message: `missing: ${m}` }));
268	}
269	
270	// checkMissingFixtures(cal, fixtureAbs) -> {entries, failed, skipped: 0}. entries is non-empty
271	// only when at least one of this calibration's fixture files does not exist on disk.
272	function checkMissingFixtures(cal, fixtureAbs) {
273	  const entries = [];
274	  let failed = 0;
275	  for (const f of fixtureAbs) {
276	    if (!fs.existsSync(f)) {
277	      entries.push({ name: cal.name, status: 'FAIL', detail: `fixture missing: ${f}` });
278	      failed++;
279	    }
280	  }
281	  return { entries, failed, skipped: 0 };
282	}
283	
284	// runInternalCalibration(cal, fixtureAbs) -> {entries, failed, skipped: 0}. The "internal": true
285	// calibration (payload-contract) runs payload/contract's validatePayload() directly rather than
286	// spawning an external checker.
287	function runInternalCalibration(cal, fixtureAbs) {
288	  const entries = [];
289	  let failed = 0;
290	  try {
291	    const findings = runInternalPayloadContract(fixtureAbs[0]);
292	    if (findings.length > 0) {
293	      entries.push({ name: cal.name, status: 'PASS', detail: `${findings.length} finding(s) on the fixture (e.g. ${findings[0].message})` });
294	    } else {
295	      entries.push({ name: cal.name, status: 'FAIL', detail: 'validatePayload() returned an EMPTY missing list on a deliberately incomplete payload - the contract gate is broken' });
296	      failed++;
297	    }
298	  } catch (e) {
299	    entries.push({ name: cal.name, status: 'FAIL', detail: `internal check errored: ${e.message}` });
300	    failed++;
301	  }
302	  return { entries, failed, skipped: 0 };
303	}
304	
305	// missingCheckerResult(cal, strict) -> the {entries,failed,skipped} result when no checker under
306	// tools/ was found for this calibration: FAIL in --strict mode (a fixture without a live checker
307	// is an unearned zero), SKIPPED otherwise (tools/ agent has not landed this gate yet).
308	function missingCheckerResult(cal, strict) {
309	  const detail = `no checker found (looked at: ${cal.checkerCandidates.join(', ')})`;
310	  if (strict) {
311	    return { entries: [{ name: cal.name, status: 'FAIL', detail: `${detail} - strict mode: a fixture without a live checker is an unearned zero` }], failed: 1, skipped: 0 };
312	  }
313	  return { entries: [{ name: cal.name, status: 'SKIPPED', detail: `${detail} - tools/ agent has not landed this gate yet; CI must flip to --strict when it does` }], failed: 0, skipped: 1 };
314	}
315	
316	// judgeCheckerFindings(cal, checker) -> {entries, failed} from running the checker and confirming
317	// EVERY fixture listed for this calibration was caught (CR-38: a multi-fixture calibration
318	// previously passed as long as ONE fixture produced a finding, so a checker could keep catching an
319	// old fixture while missing a new one).
320	function judgeCheckerFindings(cal, checker) {
321	  const findings = runExternalChecker(checker);
322	  const missingFixtures = cal.fixtures.filter((fx) => !findings.some((fd) => String(fd.file || '').includes(fx)));
323	  const fixtureHits = findings.filter((fd) => cal.fixtures.some((fx) => String(fd.file || '').includes(fx)));
324	  if (missingFixtures.length === 0) {
325	    return { entries: [{ name: cal.name, status: 'PASS', detail: `${fixtureHits.length} finding(s) across all ${cal.fixtures.length} fixture(s) via ${path.relative(REPO_ROOT, checker)}` }], failed: 0 };
326	  }
327	  return { entries: [{ name: cal.name, status: 'FAIL', detail: `${path.relative(REPO_ROOT, checker)} reported ZERO findings on: ${missingFixtures.join(', ')} - it has not earned its zero on every seeded fixture (${cal.description})` }], failed: 1 };
328	}
329	
330	// runExternalCalibration(cal, strict) -> {entries, failed, skipped}. Locates the checker under
331	// tools/ via findChecker(), reports SKIPPED (or FAIL in --strict mode) if none is found yet, and
332	// otherwise runs its --calibrate contract via runExternalChecker() and checks every listed
333	// fixture was caught. Behaviour is unchanged from the original inline version: failed/skipped are
334	// still exactly 0 or 1 per call (missingCheckerResult and judgeCheckerFindings each push exactly
335	// one entry and increment their own counter by at most 1).
336	function runExternalCalibration(cal, strict) {
337	  const checker = findChecker(cal.checkerCandidates);
338	  if (!checker) return missingCheckerResult(cal, strict);
339	  try {
340	    const { entries, failed } = judgeCheckerFindings(cal, checker);
341	    return { entries, failed, skipped: 0 };
342	  } catch (e) {
343	    return { entries: [{ name: cal.name, status: 'FAIL', detail: `checker errored or broke the --calibrate contract: ${e.message}` }], failed: 1, skipped: 0 };
344	  }
345	}
346	
347	// runOneCalibration(cal, strict) -> {entries: [...], failed: N, skipped: N} for one CALIBRATIONS
348	// entry. Semantics are UNCHANGED from the original inline loop body (do not change the
349	// CALIBRATIONS registry semantics or --strict behaviour): missing fixture files short-circuit
350	// straight to a FAIL entry per file; otherwise an "internal" calibration runs payload/contract
351	// directly and everything else runs its checker's --calibrate contract. The original loop tested
352	// `results.some((r) => r.name === cal.name && r.status === 'FAIL')` against the GLOBAL results
353	// list; since every entry pushed for earlier calibrations carries a DIFFERENT cal.name, that was
354	// already equivalent to testing only the entries just pushed for THIS calibration, which is what
355	// checkMissingFixtures's own (per-calibration) entries list does directly.
356	function runOneCalibration(cal, strict) {
357	  const fixtureAbs = cal.fixtures.map((f) => path.join(FIXTURES_DIR, f));
358	  const missing = checkMissingFixtures(cal, fixtureAbs);
359	  if (missing.entries.length > 0) return missing;
360	  if (cal.internal) return runInternalCalibration(cal, fixtureAbs);
361	  return runExternalCalibration(cal, strict);
362	}
363	
364	// report({strict, results, failed, skipped, asJson}) -> prints the run's summary in --json or
365	// human form, unchanged from the original inline block in main() (params bundled into one object;
366	// not exported, so the call site below is the only caller to update).
367	function report({ strict, results, failed, skipped, asJson }) {
368	  if (asJson) {
369	    console.log(JSON.stringify({ strict, results, failed, skipped }, null, 2));
370	    return;
371	  }
372	  console.log('calibration-known-bad: the earn-your-zero gate');
373	  for (const r of results) console.log(`  ${r.status.padEnd(7)} ${r.name}: ${r.detail}`);
374	  if (failed > 0) {
375	    console.log(`RESULT: FAIL - ${failed} gate(s) did not catch their seeded known-bad fixture. A gate that misses planted disease is reporting worthless greens.`);
376	  } else if (skipped > 0) {
377	    console.log(`RESULT: OK with ${skipped} SKIPPED - external checkers not landed yet. Flip CI to --strict once tools/ lands.`);
378	  } else {
379	    console.log('RESULT: OK - every gate caught its fixture.');
380	  }
381	}
382	
383	function main(argv) {
384	  const args = argv.slice(2);
385	  const strict = args.includes('--strict');
386	  const asJson = args.includes('--json');
387	  const unknown = args.filter((a) => !['--strict', '--json'].includes(a));
388	  if (unknown.length) {
389	    console.error(`Unknown argument(s): ${unknown.join(', ')}`);
390	    return 2;
391	  }
392	
393	  const results = [];
394	  let failed = 0;
395	  let skipped = 0;
396	
397	  for (const cal of CALIBRATIONS) {
398	    const r = runOneCalibration(cal, strict);
399	    results.push(...r.entries);
400	    failed += r.failed;
401	    skipped += r.skipped;
402	  }
403	
404	  report({ strict, results, failed, skipped, asJson });
405	  return failed > 0 ? 1 : 0;
406	}
407	
408	if (require.main === module) {
409	  process.exit(main(process.argv));
410	}
411	
412	module.exports = { CALIBRATIONS, runExternalChecker };
413

